function writeString(t,e,n){for(let s=0;s<n.length;++s)t.setUint8(e+s,n.charCodeAt(s))}class WavMaker{constructor(t=44100,e=1){this.sampleRate=t,this.numChannels=e,this.numSamples=0,this.blobs=[]}addData(t){const{numChannels:e}=this,n=t[0].length,s=n*e,a=new Uint16Array(s),i=new DataView(a.buffer);let r=0;for(let s=0;s<n;++s)for(let n=0;n<e;++n){const e=Math.max(-1,Math.min(1,t[n][s]));i.setInt16(r,e<0?32768*e:32767*e,!0),r+=2}this.blobs.push(new Blob([a])),this.numSamples+=n}getWavBlob(){const{numSamples:t,numChannels:e,sampleRate:n,blobs:s}=this;var a=new Uint8Array(44),i=new DataView(a.buffer);return writeString(i,0,"RIFF"),i.setUint32(4,36+2*this.numSamples,!0),writeString(i,8,"WAVE"),writeString(i,12,"fmt "),i.setUint32(16,16,!0),i.setUint16(20,1,!0),i.setUint16(22,e,!0),i.setUint32(24,n,!0),i.setUint32(28,n*e*2,!0),i.setUint16(32,2*e,!0),i.setUint16(34,16,!0),writeString(i,36,"data"),i.setUint32(40,t*e*2,!0),new Blob([new Blob([a]),...s],{type:"audio/wav"})}}window.WavMaker=WavMaker;